UPDATE class_configs SET skills = '[{"name":"Dark Pact","desc":"Sacrifice 10% HP, deal 75 dmg, heal 25%. 10s CD","type":"Special","params":[{"init":10,"per_lvl":2.5,"max":20},{"init":75,"per_lvl":18.75,"max":150},{"init":25,"per_lvl":6.25,"max":50}]},{"name":"Void Strike","desc":"Teleport to enemy within 8m, dealing 20-80 dark damage + heal 25% of damage. 12s CD","type":"Ability","params":[{"init":20,"per_lvl":15,"max":80},{"init":25,"per_lvl":0,"max":50}]},{"name":"Shadow Burst","desc":"Explode in 5m radius dealing 30-70 damage + 10-30% slow for 2s. 18s cooldown","type":"Ability","params":[{"init":30,"per_lvl":10,"max":70},{"init":10,"per_lvl":5,"max":30},{"init":2,"per_lvl":0,"max":2}]},{"name":"Soul Rend","desc":"Drain target within 8m for 20-60 damage, healing yourself for 10-30 HP. 15s CD","type":"Ability","params":[{"init":20,"per_lvl":10,"max":60},{"init":10,"per_lvl":5,"max":30}]},{"name":"Shadow Power","desc":"Increase dark/void damage dealt by percentage","type":"Stat","params":[{"init":5,"per_lvl":5,"max":25}]},{"name":"Eclipse","desc":"Increase damage by percentage when health is below 50%","type":"Stat","params":[{"init":4,"per_lvl":4,"max":20}]},{"name":"Vampiric Embrace","desc":"Lifesteal is 10-50% more effective. Healing from abilities 5-25% stronger. 15% base lifesteal.","type":"Passive","params":[{"init":10,"per_lvl":10,"max":50},{"init":5,"per_lvl":5,"max":25}]}]'::jsonb WHERE class_id = 'shadow_knight';
