UPDATE class_configs SET skills = '[{"name":"Control Field","desc":"6m zone: 10% slow, -5% enemy dmg, 3s. 14s CD","type":"Special","params":[{"init":10,"per_lvl":5,"max":30},{"init":-5,"per_lvl":-2.5,"max":-15},{"init":3,"per_lvl":0.75,"max":6}]},{"name":"Command","desc":"Increase control effect duration (stun/root/slow) by seconds","type":"Stat","params":[{"init":0.4,"per_lvl":0.4,"max":2}]},{"name":"Tactical Mind","desc":"Reduce control ability cooldowns by percentage","type":"Stat","params":[{"init":-3,"per_lvl":-3,"max":-15}]},{"name":"Displace","desc":"Push or pull target enemy 4-8m to new position. Single target, 10m range. 12s CD","type":"Ability","params":[{"init":4,"per_lvl":1,"max":8}]},{"name":"Tempo Lock","desc":"Enemies within your control zones deal 3-15% less damage","type":"Passive","params":[{"init":-3,"per_lvl":-3,"max":-15}]}]'::jsonb WHERE class_id = 'controller';
UPDATE class_configs SET skills = '[{"name":"Time Fracture","desc":"20% slow enemies, +10% haste exit, 2.5s. 16s CD, 35 MP","type":"Special","params":[{"init":20,"per_lvl":5,"max":40},{"init":10,"per_lvl":5,"max":30},{"init":2.5,"per_lvl":0.5,"max":4.5}]},{"name":"Slow Field","desc":"Create 6m zone slowing enemies by 20-40% for 3-5s. 20s cooldown. 30 MP","type":"Ability","params":[{"init":20,"per_lvl":5,"max":40},{"init":3,"per_lvl":0.5,"max":5}]},{"name":"Time Freeze","desc":"Freeze single target completely for 0.5-2s. 25s cooldown. 40 MP","type":"Ability","params":[{"init":0.5,"per_lvl":0.375,"max":2}]},{"name":"Rewind","desc":"Rewind position to 1-3s ago, resetting damage taken in that window. 35s CD. 50 MP","type":"Ability","params":[{"init":1,"per_lvl":0.5,"max":3}]},{"name":"Time Warp","desc":"Increase movement speed by percentage after using control abilities","type":"Stat","params":[{"init":3,"per_lvl":3,"max":15}]},{"name":"Decay","desc":"Enemies in your slow fields take 5-25 damage over time per second","type":"Stat","params":[{"init":5,"per_lvl":5,"max":25}]},{"name":"Borrowed Seconds","desc":"Control effects apply cooldown reduction burst 6-30%.","type":"Passive","params":[{"init":6,"per_lvl":6,"max":30}]}]'::jsonb WHERE class_id = 'chronomancer';
UPDATE class_configs SET skills = '[{"name":"Bastion Ring","desc":"Ring 3s: 10% slow, root first target. 18s CD","type":"Special","params":[{"init":10,"per_lvl":5,"max":30},{"init":3,"per_lvl":0.5,"max":5}]},{"name":"Ring of Thorns","desc":"Summon ring (5m radius) lasting 3-5s. Roots crossing enemies, deals 15-40 dmg/s","type":"Ability","params":[{"init":3,"per_lvl":0.5,"max":5},{"init":15,"per_lvl":6.25,"max":40},{"init":0,"per_lvl":0,"max":0}]},{"name":"Vine Snare","desc":"Summon vines rooting all enemies in 4m radius for 0.5-2s. 15s cooldown","type":"Ability","params":[{"init":0.5,"per_lvl":0.375,"max":2}]},{"name":"Bramble Wall","desc":"Erect thorn wall (6m wide, 2s duration) blocking movement, dealing 20-50 damage","type":"Ability","params":[{"init":2,"per_lvl":0,"max":2},{"init":20,"per_lvl":7.5,"max":50}]},{"name":"Fortification","desc":"Increase ring/barrier HP and duration by percentage","type":"Stat","params":[{"init":10,"per_lvl":10,"max":50}]},{"name":"Entrapment","desc":"Increase root/slow duration by seconds","type":"Stat","params":[{"init":0.4,"per_lvl":0.4,"max":2}]},{"name":"Line Holder","desc":"Enemies near your control zones deal 4-20% less damage","type":"Passive","params":[{"init":-4,"per_lvl":-4,"max":-20}]}]'::jsonb WHERE class_id = 'warden';
UPDATE class_configs SET skills = '[{"name":"Severing Hex","desc":"Cone: -5% enemy dmg, +3% ability dmg taken. 13s CD, 3s, 25 MP","type":"Special","params":[{"init":-5,"per_lvl":-3.75,"max":-20},{"init":3,"per_lvl":3,"max":15},{"init":3,"per_lvl":0.75,"max":6}]},{"name":"Hex Cone","desc":"45° cone curse: enemies deal 5-20% less damage, take 5-15% more ability damage. 20 MP","type":"Ability","params":[{"init":-5,"per_lvl":-3.75,"max":-20},{"init":5,"per_lvl":2.5,"max":15}]},{"name":"Cursed Ground","desc":"Corrupt 5m ground for 3-5s. Enemies have -10-30% stats while standing in it. 30 MP","type":"Ability","params":[{"init":3,"per_lvl":0.5,"max":5},{"init":-10,"per_lvl":-5,"max":-30}]},{"name":"Hex Bolt","desc":"Fire projectile marking single target instantly. Mark lasts 2-6s. 12s CD. 15 MP","type":"Ability","params":[{"init":2,"per_lvl":1,"max":6}]},{"name":"Dark Mark","desc":"Increase curse bonus damage by percentage","type":"Stat","params":[{"init":4,"per_lvl":4,"max":20}]},{"name":"Affliction","desc":"Increase curse debuff strength by percentage","type":"Stat","params":[{"init":3,"per_lvl":3,"max":15}]},{"name":"Malice Chain","desc":"Defeated cursed enemies spread weaker curse within 4m (10-50% chance)","type":"Passive","params":[{"init":10,"per_lvl":10,"max":50}]}]'::jsonb WHERE class_id = 'hexbinder';
UPDATE class_configs SET skills = '[{"name":"Tempest Pulse","desc":"30 dmg, knockback 2m, 1s slow. 12s CD, 25 MP","type":"Special","params":[{"init":30,"per_lvl":7.5,"max":60},{"init":2,"per_lvl":0.5,"max":4},{"init":1,"per_lvl":0.5,"max":3}]},{"name":"Shockwave","desc":"Chain of 2 shockwaves (8m range) dealing 20-60 damage + 10-30% slow for 1s. 16s CD. 25 MP","type":"Ability","params":[{"init":20,"per_lvl":10,"max":60},{"init":10,"per_lvl":5,"max":30}]},{"name":"Thunder Clap","desc":"Slam ground sending shockwave in 6m radius, stunning for 0.3-1.5s. 18s cooldown. 30 MP","type":"Ability","params":[{"init":0.3,"per_lvl":0.3,"max":1.5}]},{"name":"Static Field","desc":"Charge self for 4-8s. Enemies within 4m take 5-20 damage when they hit you. 20 MP","type":"Ability","params":[{"init":4,"per_lvl":1,"max":8},{"init":5,"per_lvl":3.75,"max":20}]},{"name":"Voltage","desc":"Increase lightning damage dealt by percentage","type":"Stat","params":[{"init":5,"per_lvl":5,"max":25}]},{"name":"Surge","desc":"Increase knockback distance and stun duration by percentage","type":"Stat","params":[{"init":10,"per_lvl":10,"max":50}]},{"name":"Static Build","desc":"Each consecutive hit on controlled target adds +1-5% lightning damage, up to +5-25%","type":"Passive","params":[{"init":1,"per_lvl":1,"max":5},{"init":5,"per_lvl":5,"max":25}]}]'::jsonb WHERE class_id = 'stormcaller';
